  1→package com.exam.service;
  2→
  3→import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
  4→import com.exam.dto.QuestionBatchRequest;
  5→import com.exam.dto.QuestionCreateRequest;
  6→import com.exam.dto.QuestionItem;
  7→import com.exam.entity.Exam;
  8→import com.exam.entity.QuestionBank;
  9→import com.exam.enums.ExamStatus;
 10→import com.exam.exception.BizException;
 11→import com.exam.exception.ErrorCode;
 12→import com.exam.mapper.ExamMapper;
 13→import com.exam.mapper.QuestionBankMapper;
 14→import lombok.extern.slf4j.Slf4j;
 15→import org.springframework.stereotype.Service;
 16→import org.springframework.transaction.annotation.Transactional;
 17→
 18→import java.util.ArrayList;
 19→import java.util.List;
 20→
 21→/**
 22→ * 题目管理服务
 23→ */
 24→@Slf4j
 25→@Service
 26→public class QuestionService {
 27→
 28→    private final QuestionBankMapper questionBankMapper;
 29→    private final ExamMapper examMapper;
 30→
 31→    public QuestionService(QuestionBankMapper questionBankMapper, ExamMapper examMapper) {
 32→        this.questionBankMapper = questionBankMapper;
 33→        this.examMapper = examMapper;
 34→    }
 35→
 36→    /**
 37→     * 查询指定试卷的题目列表，按排序号升序
 38→     */
 39→    public List<QuestionBank> list(Long examId) {
 40→        return questionBankMapper.selectList(
 41→                new LambdaQueryWrapper<QuestionBank>()
 42→                        .eq(QuestionBank::getExamId, examId)
 43→                        .orderByAsc(QuestionBank::getSortOrder));
 44→    }
 45→
 46→    /**
 47→     * 创建单道题目
 48→     */
 49→    public QuestionBank create(Long examId, QuestionCreateRequest req) {
 50→        checkExamDraft(examId);
 51→        int maxSort = getMaxSortOrder(examId);
 52→        QuestionBank question = QuestionBank.builder()
 53→                .examId(examId)
 54→                .content(req.getContent())
 55→                .optionA(req.getOptionA())
 56→                .optionB(req.getOptionB())
 57→                .optionC(req.getOptionC())
 58→                .optionD(req.getOptionD())
 59→                .correctAnswer(req.getCorrectAnswer())
 60→                .analysis(req.getAnalysis())
 61→                .sortOrder(maxSort + 1)
 62→                .build();
 63→        questionBankMapper.insert(question);
 64→        log.info("[lbl][Question][CREATE] 创建题目, questionId={}, examId={}", question.getId(), examId);
 65→        return question;
 66→    }
 67→
 68→    /**
 69→     * 批量导入题目
 70→     */
 71→    @Transactional(rollbackFor = Exception.class)
 72→    public int batchCreate(Long examId, QuestionBatchRequest req) {
 73→        checkExamDraft(examId);
 74→        int maxSort = getMaxSortOrder(examId);
 75→        List<QuestionItem> items = req.getQuestions();
 76→        for (QuestionItem item : items) {
 77→            maxSort++;
 78→            QuestionBank question = QuestionBank.builder()
 79→                    .examId(examId)
 80→                    .content(item.getContent())
 81→                    .optionA(item.getOptionA())
 82→                    .optionB(item.getOptionB())
 83→                    .optionC(item.getOptionC())
 84→                    .optionD(item.getOptionD())
 85→                    .correctAnswer(item.getCorrectAnswer())
 86→                    .analysis(item.getAnalysis())
 87→                    .sortOrder(maxSort)
 88→                    .build();
 89→            questionBankMapper.insert(question);
 90→        }
 91→        log.info("[lbl][Question][BATCH_CREATE] 批量导入题目, examId={}, count={}", examId, items.size());
 92→        return items.size();
 93→    }
 94→
 95→    /**
 96→     * 更新题目
 97→     */
 98→    public void update(Long questionId, QuestionCreateRequest req) {
 99→        QuestionBank question = questionBankMapper.selectById(questionId);
100→        if (question == null) {
101→            throw new BizException(ErrorCode.NOT_FOUND);
102→        }
103→        checkExamDraft(question.getExamId());
104→        question.setContent(req.getContent());
105→        question.setOptionA(req.getOptionA());
106→        question.setOptionB(req.getOptionB());
107→        question.setOptionC(req.getOptionC());
108→        question.setOptionD(req.getOptionD());
109→        question.setCorrectAnswer(req.getCorrectAnswer());
110→        question.setAnalysis(req.getAnalysis());
111→        questionBankMapper.updateById(question);
112→        log.info("[lbl][Question][UPDATE] 更新题目, questionId={}, examId={}", questionId, question.getExamId());
113→    }
114→
115→    /**
116→     * 删除题目
117→     */
118→    public void delete(Long questionId) {
119→        QuestionBank question = questionBankMapper.selectById(questionId);
120→        if (question == null) {
121→            throw new BizException(ErrorCode.NOT_FOUND);
122→        }
123→        checkExamDraft(question.getExamId());
124→        questionBankMapper.deleteById(questionId);
125→        log.info("[lbl][Question][DELETE] 删除题目, questionId={}, examId={}", questionId, question.getExamId());
126→    }
127→
128→    /**
129→     * 校验试卷是否为草稿状态，非草稿抛出异常
130→     */
131→    private void checkExamDraft(Long examId) {
132→        Exam exam = examMapper.selectById(examId);
133→        if (exam == null) {
134→            throw new BizException(ErrorCode.NOT_FOUND);
135→        }
136→        if (exam.getStatus() != ExamStatus.DRAFT) {
137→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
138→        }
139→    }
140→
141→    /**
142→     * 获取指定试卷当前最大排序号，无题目时返回 0
143→     */
144→    private int getMaxSortOrder(Long examId) {
145→        LambdaQueryWrapper<QuestionBank> wrapper = new LambdaQueryWrapper<QuestionBank>()
146→                .eq(QuestionBank::getExamId, examId)
147→                .orderByDesc(QuestionBank::getSortOrder)
148→                .last("LIMIT 1");
149→        QuestionBank last = questionBankMapper.selectOne(wrapper);
150→        return last == null ? 0 : last.getSortOrder();
151→    }
152→}
