 1→package com.exam.dto;
 2→
 3→import com.exam.exception.ErrorCode;
 4→import lombok.Data;
 5→
 6→/**
 7→ * 统一返回体
 8→ */
 9→@Data
10→public class Result<T> {
11→
12→    private int code;
13→    private String message;
14→    private T data;
15→
16→    private Result(int code, String message, T data) {
17→        this.code = code;
18→        this.message = message;
19→        this.data = data;
20→    }
21→
22→    public static <T> Result<T> ok(T data) {
23→        return new Result<>(ErrorCode.SUCCESS.getCode(), ErrorCode.SUCCESS.getMessage(), data);
24→    }
25→
26→    public static <T> Result<T> ok() {
27→        return ok(null);
28→    }
29→
30→    public static <T> Result<T> fail(ErrorCode errorCode) {
31→        return new Result<>(errorCode.getCode(), errorCode.getMessage(), null);
32→    }
33→
34→    public static <T> Result<T> fail(int code, String message) {
35→        return new Result<>(code, message, null);
36→    }
37→}
