const REQUIRED_FIELDS = ["content", "optionA", "optionB", "optionC", "optionD", "correctAnswer"] as const

/** 校验单条题目数据 */
const validateQuestion = (item: Record<string, unknown>, index: number): string | null => {
  for (const field of REQUIRED_FIELDS) {
    if (!item[field] || typeof item[field] !== "string" || !(item[field] as string).trim()) {
      return t("admin.invalidQuestionData", { index: index + 1 })
    }
  }
  if (!/^[ABCD]$/.test(item.correctAnswer as string)) {
    return t("admin.invalidQuestionData", { index: index + 1 })
  }
  return null
}

/** 处理文件选择 */
const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
  const file = e.target.files?.[0]
  if (!file) return
  const reader = new FileReader()
  reader.onload = (event) => {
    try {
      const parsed = JSON.parse(event.target?.result as string)
      const items = Array.isArray(parsed) ? parsed : parsed.questions
      if (!Array.isArray(items) || items.length === 0) {
        toast.error(t("admin.invalidJsonFormat"))
        return
      }
      // 逐条校验
      for (let i = 0; i < items.length; i++) {
        const err = validateQuestion(items[i], i)
        if (err) {
          toast.error(err)
          return
        }
      }
      setImportPreview(items)
    } catch {
      toast.error(t("admin.invalidJsonFormat"))
    }
  }
  reader.onerror = () => toast.error(t("admin.fileReadError"))
  reader.readAsText(file)
  // 重置 input，允许重复选择同一文件
  e.target.value = ""
}

/** 确认导入 */
const handleImportConfirm = () => {
  if (!importPreview) return
  batchImportMutation.mutate(
    { examId, questions: importPreview },
    {
      onSuccess: () => {
        toast.success(t("admin.importSuccess", { count: importPreview.length }))
        setShowImportDialog(false)
        setImportPreview(null)
      },
      onError: (err) => toast.error(err.message),
    },
  )
}

