 24→
 25→/**
 26→ * 试卷服务
 27→ */
 28→@Slf4j
 29→@Service
 30→public class ExamService {
 31→
 32→    private final ExamMapper examMapper;
 33→    private final QuestionBankMapper questionBankMapper;
 34→    private final SysUserMapper sysUserMapper;
 35→    private final ExamRecordMapper examRecordMapper;
 36→    private final ExamRecordQuestionMapper examRecordQuestionMapper;
 37→    private final AnswerDetailMapper answerDetailMapper;
 38→
 39→    public ExamService(ExamMapper examMapper, QuestionBankMapper questionBankMapper,
 40→                       SysUserMapper sysUserMapper, ExamRecordMapper examRecordMapper,
 41→                       ExamRecordQuestionMapper examRecordQuestionMapper,
 42→                       AnswerDetailMapper answerDetailMapper) {
 43→        this.examMapper = examMapper;
 44→        this.questionBankMapper = questionBankMapper;
 45→        this.sysUserMapper = sysUserMapper;
 46→        this.examRecordMapper = examRecordMapper;
 47→        this.examRecordQuestionMapper = examRecordQuestionMapper;
 48→        this.answerDetailMapper = answerDetailMapper;
 49→    }
 50→
 51→    /**
 52→     * 分页查询试卷列表（含答卷人数）
 53→     */
 54→    public IPage<ExamListResponse> listExams(int page, int size) {
 55→        return examMapper.selectExamListWithCount(new Page<>(page, size));
 56→    }
 57→
 58→    /**
 59→     * 创建试卷（初始状态为草稿）
 60→     */
 61→    public Exam create(ExamCreateRequest req, Long userId) {
 62→        Exam exam = Exam.builder()
 63→                .title(req.getTitle())
 64→                .timeLimitMin(req.getTimeLimitMin())
 65→                .showAnswer(req.getShowAnswer())
 66→                .showAnalysis(req.getShowAnalysis())
 67→                .questionCount(req.getQuestionCount())
 68→                .maxAttempts(req.getMaxAttempts())
 69→                .accessMode(req.getAccessMode())
 70→                .status(ExamStatus.DRAFT)
 71→                .createdBy(userId)
 72→                .build();
 73→        examMapper.insert(exam);
 74→        log.info("[lbl][Exam][CREATE] 创建试卷, examId={}, userId={}", exam.getId(), userId);
 75→        return exam;
 76→    }
 77→
 78→    /**
 79→     * 更新试卷（仅草稿状态可编辑）
 80→     */
 81→    public void update(Long id, ExamUpdateRequest req) {
 82→        Exam exam = getExamOrThrow(id);
 83→        if (exam.getStatus() != ExamStatus.DRAFT) {
 84→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
 85→        }
 86→        exam.setTitle(req.getTitle());
 87→        exam.setTimeLimitMin(req.getTimeLimitMin());
 88→        exam.setShowAnswer(req.getShowAnswer());
 89→        exam.setShowAnalysis(req.getShowAnalysis());
 90→        exam.setQuestionCount(req.getQuestionCount());
 91→        exam.setMaxAttempts(req.getMaxAttempts());
 92→        exam.setAccessMode(req.getAccessMode());
 93→        examMapper.updateById(exam);
 94→        log.info("[lbl][Exam][UPDATE] 更新试卷, examId={}", id);
 95→    }
 96→
 97→    /**
 98→     * 删除试卷（草稿或已关闭状态可删除，已发布状态需先关闭或取消发布）
 99→     */
100→    public void delete(Long id) {
101→        Exam exam = getExamOrThrow(id);
102→        if (exam.getStatus() == ExamStatus.PUBLISHED) {
103→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
104→        }
105→        examMapper.deleteById(id);
106→        log.info("[lbl][Exam][DELETE] 删除试卷, examId={}, status={}", id, exam.getStatus());
107→    }
108→
109→    /**
110→     * 发布试卷（草稿 -> 已发布，需至少有一道题目）
111→     */
112→    public void publish(Long id) {
113→        Exam exam = getExamOrThrow(id);
114→        if (exam.getStatus() != ExamStatus.DRAFT) {
115→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
116→        }
117→        // 校验题目数量
118→        long questionCount = questionBankMapper.selectCount(
119→                new LambdaQueryWrapper<QuestionBank>().eq(QuestionBank::getExamId, id));
120→        if (questionCount == 0) {
121→            throw new BizException(ErrorCode.EXAM_NO_QUESTIONS);
122→        }
123→        exam.setStatus(ExamStatus.PUBLISHED);
124→        examMapper.updateById(exam);
125→        log.info("[lbl][Exam][PUBLISH] 发布试卷, examId={}, questionCount={}", id, questionCount);
126→    }
127→
128→    /**
129→     * 取消发布试卷（已发布 -> 草稿）
130→     */
131→    public void unpublish(Long id) {
132→        Exam exam = getExamOrThrow(id);
133→        if (exam.getStatus() != ExamStatus.PUBLISHED) {
134→            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
135→        }
136→        exam.setStatus(ExamStatus.DRAFT);
137→        examMapper.updateById(exam);
138→        log.info("[lbl][Exam][UNPUBLISH] 取消发布试卷, examId={}", id);
139→    }
140→
141→    /**
142→     * 关闭试卷（已发布 -> 已关闭）
143→     */
144→    public void close(Long id) {
145→        Exam exam = getExamOrThrow(id);
146→        if (exam.getStatus() != ExamStatus.PUBLISHED) {
147→            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
148→        }
149→        exam.setStatus(ExamStatus.CLOSED);
150→        examMapper.updateById(exam);
151→        log.info("[lbl][Exam][CLOSE] 关闭试卷, examId={}", id);
152→    }
153→
154→    /**
155→     * 重新开放试卷（已关闭 -> 已发布）
156→     */
157→    public void reopen(Long id) {
158→        Exam exam = getExamOrThrow(id);
159→        if (exam.getStatus() != ExamStatus.CLOSED) {
160→            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
161→        }
162→        exam.setStatus(ExamStatus.PUBLISHED);
163→        examMapper.updateById(exam);
164→        log.info("[lbl][Exam][REOPEN] 重新开放试卷, examId={}", id);
165→    }
166→
167→    /**
168→     * Mock 考试数据：批量创建模拟用户并随机答题
169→     *
170→     * @param examId    试卷ID（null 则随机选一个已发布试卷）
171→     * @param userCount 模拟用户数量
172→     * @return 生成的考试记录数
173→     */
174→    @Transactional(rollbackFor = Exception.class)
175→    public int mockExam(Long examId, int userCount) {
176→        // 1. 确定试卷
177→        Exam exam;
178→        if (examId != null) {
179→            exam = getExamOrThrow(examId);
180→        } else {
181→            List<Exam> publishedExams = examMapper.selectList(
182→                    new LambdaQueryWrapper<Exam>().eq(Exam::getStatus, ExamStatus.PUBLISHED));
183→            if (publishedExams.isEmpty()) {
184→                // 也查已关闭的试卷
185→                publishedExams = examMapper.selectList(
186→                        new LambdaQueryWrapper<Exam>().eq(Exam::getStatus, ExamStatus.CLOSED));
187→            }
188→            if (publishedExams.isEmpty()) {
189→                throw new BizException(ErrorCode.NOT_FOUND);
190→            }
191→            exam = publishedExams.get(ThreadLocalRandom.current().nextInt(publishedExams.size()));
