import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { ArrowLeft } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { useRecordDetail } from "@/hooks/use-records"
import { cn } from "@/lib/utils"

export const Route = createFileRoute("/_layout/records/$id")({
  component: RecordDetailPage,
})

const OPTION_KEYS = ["A", "B", "C", "D"] as const

/** 计算用时，返回格式化字符串 */
function formatDuration(
  startTime: string,
  endTime: string | null,
  t: (key: string, opts?: Record<string, unknown>) => string,
): string {
  if (!endTime) return "-"
  const diffMs = new Date(endTime).getTime() - new Date(startTime).getTime()
  const totalMin = Math.floor(diffMs / 60000)
  const secs = Math.floor((diffMs % 60000) / 1000)
  return t("exam.durationValue", { min: totalMin, sec: secs })
}

function RecordDetailPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = Route.useParams()
  const recordId = Number(id)
  const { data: record, isLoading } = useRecordDetail(recordId)

  if (isLoading) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.loading")}
      </div>
    )
  }

  if (!record) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.noData")}
      </div>
    )
  }

  const statusLabel =
    record.status === "submitted"
      ? t("exam.statusSubmitted")
      : record.status === "timeout"
        ? t("exam.statusTimeout")
        : t("exam.statusInProgress")

  const statusVariant =
    record.status === "timeout" ? "destructive" : "default"

  return (
    <div className="mx-auto max-w-3xl space-y-6">
      {/* 返回按钮 */}
      <Button
        variant="ghost"
        size="sm"
        onClick={() => navigate({ to: "/records" })}
      >
        <ArrowLeft className="mr-1 h-4 w-4" />
        {t("common.back")}
      </Button>

      {/* 成绩概要 */}
      <div className="rounded-lg border p-6 text-center space-y-3">
        <h2 className="text-lg font-semibold">{record.examTitle}</h2>
        <div className="text-4xl font-bold text-primary">
          {record.score !== null ? record.score : "-"}
          <span className="text-lg text-muted-foreground">
            {t("exam.scoreUnit")}
          </span>
        </div>
        <div className="flex items-center justify-center gap-4 text-sm text-muted-foreground">
          <Badge variant={statusVariant}>{statusLabel}</Badge>
          <span>
            {t("exam.duration")}:{" "}
            {formatDuration(record.startTime, record.endTime, t)}
          </span>
        </div>
      </div>

      {/* 答题明细 */}
      {record.answers?.length ? (
        <div className="space-y-4">
          <h3 className="text-base font-semibold">{t("exam.answerReview")}</h3>

          {record.answers.map((answer, idx) => (
            <div key={answer.questionId} className="rounded-lg border p-5 space-y-3">
              {/* 题号 + 内容 */}
              <p className="text-sm font-medium">
                <span className="text-muted-foreground">{idx + 1}. </span>
                {answer.content}
              </p>

              {/* 四个选项 */}
              <div className="space-y-1.5 pl-4">
                {OPTION_KEYS.map((key) => {
                  const optionField =
                    `option${key}` as keyof typeof answer
                  const optionText = answer[optionField] as string
                  const isUserAnswer = answer.userAnswer === key
                  const isCorrectAnswer = answer.correctAnswer === key

                  return (
                    <div
                      key={key}
                      className={cn(
                        "rounded px-2 py-1 text-sm",
                        isUserAnswer && answer.isCorrect && "bg-green-100 text-green-800",
                        isUserAnswer && !answer.isCorrect && "bg-red-100 text-red-800",
                        isCorrectAnswer && !isUserAnswer && "bg-green-50 text-green-700",
                      )}
                    >
                      {key}. {optionText}
                      {isUserAnswer && (
                        <span className="ml-2 text-xs font-medium">
                          [{t("exam.yourAnswer")}]
                        </span>
                      )}
                      {isCorrectAnswer && !isUserAnswer && (
                        <span className="ml-2 text-xs font-medium">
                          [{t("exam.correctAnswer")}]
                        </span>
                      )}
                    </div>
                  )
                })}
              </div>

              {/* 解析 */}
              {answer.analysis && (
                <>
                  <Separator />
                  <div className="rounded bg-muted p-3 text-sm text-muted-foreground">
                    <span className="font-medium">{t("exam.analysis")}: </span>
                    {answer.analysis}
                  </div>
                </>
              )}
            </div>
          ))}
        </div>
      ) : null}
    </div>
  )
}

