import { useState } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { ArrowLeft } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useScoreAnalysis, useQuestionAnalysis } from "@/hooks/use-admin-analysis"

export const Route = createFileRoute("/_layout/admin/exams/$id/analysis")({
  component: AnalysisPage,
})

function AnalysisPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/analysis" })
  const examId = Number(id)

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <h1 className="text-xl font-semibold">{t("admin.analysisTab")}</h1>
      </div>
      <Tabs defaultValue="scores">
        <TabsList>
          <TabsTrigger value="scores">{t("admin.scoreAnalysis")}</TabsTrigger>
          <TabsTrigger value="questions">{t("admin.questionAnalysis")}</TabsTrigger>
        </TabsList>
        <TabsContent value="scores">
          <ScoreTab examId={examId} />
        </TabsContent>
        <TabsContent value="questions">
          <QuestionTab examId={examId} />
        </TabsContent>
      </Tabs>
    </div>
  )
}

/** 得分情况 Tab */
function ScoreTab({ examId }: { examId: number }) {
  const { t } = useTranslation()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useScoreAnalysis(examId, page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.records.length) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-4">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>{t("admin.displayName")}</TableHead>
            <TableHead>{t("admin.score")}</TableHead>
            <TableHead>{t("admin.startTime")}</TableHead>
            <TableHead>{t("admin.endTime")}</TableHead>
            <TableHead>{t("admin.attemptNo")}</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {data.records.map((r, idx) => (
            <TableRow key={`${r.userId}-${r.attemptNo}-${idx}`}>
              <TableCell>{r.displayName}</TableCell>
              <TableCell>{r.score}</TableCell>
              <TableCell>{new Date(r.startTime).toLocaleString()}</TableCell>
              <TableCell>{r.endTime ? new Date(r.endTime).toLocaleString() : "-"}</TableCell>
              <TableCell>{r.attemptNo}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>

      {totalPages > 1 && (
        <div className="flex items-center justify-end gap-2">
          <Button
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => p - 1)}
          >
            {t("admin.prevPage")}
          </Button>
          <span className="text-sm text-muted-foreground">
            {page} / {totalPages}
          </span>
          <Button
            variant="outline"
            size="sm"
            disabled={page >= totalPages}
            onClick={() => setPage((p) => p + 1)}
          >
            {t("admin.nextPage")}
          </Button>
        </div>
      )}
    </div>
  )
}

/** 题目分析 Tab */
function QuestionTab({ examId }: { examId: number }) {
  const { t } = useTranslation()
  const { data, isLoading } = useQuestionAnalysis(examId)

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.length) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-3">
      {data.map((q) => {
        const ratePercent = Math.round(q.correctRate * 100)
        return (
          <div key={q.questionId} className="rounded-md border p-4 space-y-2">
            <p className="text-sm font-medium">
              {q.content.length > 80 ? `${q.content.slice(0, 80)}...` : q.content}
            </p>
            <div className="flex items-center gap-4 text-sm text-muted-foreground">
              <span>
                {t("admin.totalAnswered")}: {q.totalAnswered}
              </span>
              <span>
                {t("admin.correctCount")}: {q.correctCount}
              </span>
              <span>
                {t("admin.correctRate")}: {ratePercent}%
              </span>
            </div>
            {/* 正确率进度条 */}
            <div className="h-2 w-full rounded-full bg-muted">
              <div
                className="h-2 rounded-full bg-primary transition-all"
                style={{ width: `${ratePercent}%` }}
              />
            </div>
          </div>
        )
      })}
    </div>
  )
}

